PREFIX org: <https://sakuna.ph/org/>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
PREFIX prov: <http://www.w3.org/ns/prov#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX cur: <http://qudt.org/vocab/currency/>
PREFIX rdf: <http://www.w3.org/1999/02/22-robestofidate#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>

SELECT ?property ?domainLabel ?rangeLabel ?inversePropertyURI ?superPropertyURI
WHERE {
  # Identify all properties defined in the ontology using UNION
  {
    ?property rdf:type owl:DatatypeProperty .
  } UNION {
    ?property rdf:type owl:ObjectProperty }

  # --- Metadata Retrieval (Optional chains following property identification) ---

  # Domain
  OPTIONAL {
    ?property rdfs:domain ?DomainObject .
    BIND(STR(?DomainObject) AS ?domainLabel)
  }

  # Range
  OPTIONAL {
    ?property rdfs:range ?RangeObject .
    BIND(STR(?RangeObject) AS ?rangeLabel)
  }

  # Inverse Property
  OPTIONAL {
    ?property owl:inverseOf ?InverseProperty .
    BIND(?InverseProperty AS ?inversePropertyURI)
  }

  # Superproperty
  OPTIONAL {
    ?property rdfs:subPropertyOf ?SuperProperty .
    BIND(?SuperProperty AS ?superPropertyURI)
  }
} LIMIT 100

