PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX cur: <http://qudt.org/vocab/currency/>

SELECT DISTINCT ?negativeRecordType ?amount WHERE {
    {
        # Casualties count is negative
        ?casualty a :Casualties ;
                   :casualtyCount ?amount . FILTER (?amount < 0)
        BIND("Casualties Count" AS ?negativeRecordType)
    } UNION {
        # Affected Population count is negative
        ?population a :AffectedPopulation ;
                    :affectedPersons ?amount . FILTER (?amount < 0)
        BIND("Affected Population Count" AS ?negativeRecordType)
    } UNION {
        # Housing Damage count is negative
        ?housing a :HousingDamage ;
                 :totallyDamagedHouses ?amount . FILTER (?amount < 0)
        BIND("Housing Damage Count" AS ?negativeRecordType)
    } UNION {
        # Infrastructure Damage amount is negative
        ?inf a :InfrastructureDamage ;
              :infraDamageAmount ?amount . FILTER (?amount < 0)
        BIND("Infrastructure Damage Amount" AS ?negativeRecordType)
    } UNION {
        # Agriculture Damage amount is negative (using production loss cost as an example)
        ?agri a :AgricultureDamage ;
              :productionLossCost ?amount . FILTER (?amount < 0)
        BIND("Agriculture Damage Cost" AS ?negativeRecordType)
    }
}
